/**
 * Step 2 of the SFX pipeline — the audio sibling of review-server.mjs.
 *
 * Serves a local page where you audition the candidate clips generated by
 * tools/scripts/sfx/generate-sfx.mjs (step 1) and approve the best one per sound key.
 * Approving is instant and does the finalize in one go:
 *   - records your pick in tools/data/sfx-selections.json (committed)
 *   - copies the chosen clip to public/audio/sfx/<key>.mp3
 *   - regenerates src/data/sfx.ts so the game plays it (see src/lib/sounds.ts)
 *
 * Clearing a pick removes the public clip and the manifest entry, so the key
 * falls back to its procedural Web Audio version.
 *
 * Usage:
 *   node tools/scripts/sfx/sfx-review-server.mjs      then open http://localhost:4401
 */

import { createServer } from "http";
import {
  readFileSync,
  writeFileSync,
  existsSync,
  mkdirSync,
  copyFileSync,
  rmSync,
} from "fs";
import { join, dirname, extname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..", "..", "..");
const DATA = join(ROOT, "tools", "data");
const CAND_DIR = join(DATA, "sfx-candidates");
const INDEX_PATH = join(DATA, "sfx-candidates.json");
const SELECTIONS_PATH = join(DATA, "sfx-selections.json");
const PUBLIC_DIR = join(ROOT, "public", "audio", "sfx");
const MANIFEST_PATH = join(ROOT, "src", "data", "sfx.ts");
const PORT = Number(process.env.PORT || 4401); // 4399 vocab, 4400 find-image, 4401 sfx

if (!existsSync(INDEX_PATH)) {
  console.error("No candidates yet — run node tools/scripts/sfx/generate-sfx.mjs first.");
  process.exit(1);
}

const loadJSON = (p, fallback) =>
  existsSync(p) ? JSON.parse(readFileSync(p, "utf8")) : fallback;

// ── regenerate src/data/sfx.ts from the current selections ──
function writeManifest(selections) {
  const keys = Object.keys(selections).filter((k) => selections[k]).sort();
  const entries = keys
    .map((k) => `  ${JSON.stringify(k)}: ${JSON.stringify(`/audio/sfx/${k}.mp3`)},`)
    .join("\n");
  writeFileSync(
    MANIFEST_PATH,
    `// AUTO-GENERATED by tools/scripts/sfx/sfx-review-server.mjs — do not edit by hand.
// Maps a sound key -> approved ElevenLabs clip path. Keys not listed here fall
// back to the procedural Web Audio version in src/lib/sounds.ts.
// Regenerate by approving clips in the SFX review server.
export const sfxAssets: Record<string, string> = {
${entries}${entries ? "\n" : ""}};
`
  );
}

// ── approve: copy candidate -> public, record pick, rebuild manifest ──
function approve(key, candidateRel) {
  mkdirSync(PUBLIC_DIR, { recursive: true });
  const srcPath = join(DATA, candidateRel);
  if (!existsSync(srcPath)) throw new Error(`candidate not found: ${candidateRel}`);
  copyFileSync(srcPath, join(PUBLIC_DIR, `${key}.mp3`));
  const selections = loadJSON(SELECTIONS_PATH, {});
  selections[key] = candidateRel;
  writeFileSync(SELECTIONS_PATH, JSON.stringify(selections, null, 2) + "\n");
  writeManifest(selections);
  return selections;
}

function clear(key) {
  const selections = loadJSON(SELECTIONS_PATH, {});
  delete selections[key];
  writeFileSync(SELECTIONS_PATH, JSON.stringify(selections, null, 2) + "\n");
  const pub = join(PUBLIC_DIR, `${key}.mp3`);
  if (existsSync(pub)) rmSync(pub);
  writeManifest(selections);
  return selections;
}

const MIME = { ".mp3": "audio/mpeg", ".json": "application/json" };

const page = () => `<!doctype html>
<html><head><meta charset="utf-8"><title>SFX review</title>
<style>
  :root { color-scheme: dark; }
  body { font: 15px/1.5 system-ui, sans-serif; margin: 0; background: #15171c; color: #e6e8ec; }
  header { padding: 16px 24px; border-bottom: 1px solid #2a2e37; }
  header h1 { margin: 0; font-size: 18px; }
  header p { margin: 4px 0 0; color: #9aa1ac; font-size: 13px; }
  main { padding: 24px; display: grid; gap: 20px; max-width: 760px; }
  .key { background: #1c1f26; border: 1px solid #2a2e37; border-radius: 10px; padding: 16px; }
  .key h2 { margin: 0 0 2px; font-size: 16px; }
  .key .meta { color: #9aa1ac; font-size: 12px; margin-bottom: 12px; }
  .cand { display: flex; align-items: center; gap: 12px; padding: 8px 0; border-top: 1px solid #23262e; }
  .cand:first-of-type { border-top: 0; }
  .cand audio { height: 34px; flex: 1; }
  .cand .n { width: 22px; color: #9aa1ac; font-variant-numeric: tabular-nums; }
  button { font: inherit; padding: 6px 12px; border-radius: 7px; border: 1px solid #3a4150;
    background: #262b34; color: #e6e8ec; cursor: pointer; }
  button:hover { background: #2f3540; }
  button.approve.on { background: #2e7d46; border-color: #2e7d46; color: #fff; }
  .clear { font-size: 12px; color: #9aa1ac; background: transparent; border: 0; }
  .badge { font-size: 11px; padding: 2px 8px; border-radius: 999px; background: #2e7d46; color: #fff; }
  .badge.none { background: #3a4150; color: #c7ccd4; }
</style></head>
<body>
  <header>
    <h1>SFX review</h1>
    <p>Approve one clip per key. Approving copies it into the build and updates src/data/sfx.ts. Unapproved keys use the procedural fallback.</p>
  </header>
  <main id="app">loading…</main>
<script>
let state = { index: {}, selections: {} };

async function load() {
  state = await (await fetch("/state")).json();
  render();
}

function render() {
  const app = document.getElementById("app");
  const keys = Object.keys(state.index);
  app.innerHTML = keys.map((key) => {
    const cands = state.index[key] || [];
    const picked = state.selections[key];
    const badge = picked
      ? '<span class="badge">approved</span>'
      : '<span class="badge none">procedural fallback</span>';
    const rows = cands.map((rel, i) => {
      const on = picked === rel ? " on" : "";
      return \`<div class="cand">
        <span class="n">\${i + 1}</span>
        <audio controls preload="none" src="/file?p=\${encodeURIComponent(rel)}"></audio>
        <button class="approve\${on}" onclick="approve('\${key}','\${rel}')">\${on ? "approved" : "approve"}</button>
      </div>\`;
    }).join("");
    return \`<section class="key">
      <h2>\${key} \${badge}</h2>
      <div class="meta">\${cands.length} candidate(s)\${picked ? " · "+picked.split("/").pop() : ""}
        \${picked ? '<button class="clear" onclick="clearKey(\\''+key+'\\')">clear</button>' : ""}</div>
      \${rows || "<em>no candidates — run generate-sfx.mjs</em>"}
    </section>\`;
  }).join("");
}

async function approve(key, rel) {
  state.selections = await (await fetch("/approve", {
    method: "POST", headers: { "content-type": "application/json" },
    body: JSON.stringify({ key, rel }),
  })).json();
  render();
}
async function clearKey(key) {
  state.selections = await (await fetch("/clear", {
    method: "POST", headers: { "content-type": "application/json" },
    body: JSON.stringify({ key }),
  })).json();
  render();
}
load();
</script>
</body></html>`;

const readBody = (req) =>
  new Promise((resolve) => {
    let b = "";
    req.on("data", (c) => (b += c));
    req.on("end", () => resolve(b ? JSON.parse(b) : {}));
  });

createServer(async (req, res) => {
  const url = new URL(req.url, `http://localhost:${PORT}`);
  try {
    if (url.pathname === "/") {
      res.writeHead(200, { "content-type": "text/html" });
      return res.end(page());
    }
    if (url.pathname === "/state") {
      res.writeHead(200, { "content-type": "application/json" });
      return res.end(
        JSON.stringify({
          index: loadJSON(INDEX_PATH, {}),
          selections: loadJSON(SELECTIONS_PATH, {}),
        })
      );
    }
    if (url.pathname === "/file") {
      // Only serve from inside the candidates dir (no path traversal).
      const rel = url.searchParams.get("p") || "";
      const abs = join(DATA, rel);
      if (!abs.startsWith(CAND_DIR) || !existsSync(abs)) {
        res.writeHead(404);
        return res.end("not found");
      }
      res.writeHead(200, { "content-type": MIME[extname(abs)] || "application/octet-stream" });
      return res.end(readFileSync(abs));
    }
    if (url.pathname === "/approve" && req.method === "POST") {
      const { key, rel } = await readBody(req);
      const selections = approve(key, rel);
      console.log(`approved ${key} -> ${rel}`);
      res.writeHead(200, { "content-type": "application/json" });
      return res.end(JSON.stringify(selections));
    }
    if (url.pathname === "/clear" && req.method === "POST") {
      const { key } = await readBody(req);
      const selections = clear(key);
      console.log(`cleared ${key}`);
      res.writeHead(200, { "content-type": "application/json" });
      return res.end(JSON.stringify(selections));
    }
    res.writeHead(404);
    res.end("not found");
  } catch (e) {
    console.error(e);
    res.writeHead(500);
    res.end(String(e));
  }
}).listen(PORT, () => {
  console.log(`SFX review → http://localhost:${PORT}`);
});
